 17→// ExportCSV returns an HTTP handler that streams search results as a CSV file.
 18→// It reads filter, sort, and user-location parameters from the query string,
 19→// builds a search query capped at maxRows, and writes the results as CSV.
 20→func ExportCSV(pool *pgxpool.Pool, reg *search.Registry, maxRows int) http.HandlerFunc {
 21→	return func(w http.ResponseWriter, r *http.Request) {
 22→		q := r.URL.Query()
 23→
 24→		// Parse filters from query param.
 25→		var filters []search.FilterInput
 26→		if filtersParam := q.Get("filters"); filtersParam != "" {
 27→			if err := json.Unmarshal([]byte(filtersParam), &filters); err != nil {
 28→				writeJSONError(w, http.StatusBadRequest,
 29→					fmt.Sprintf("handler: invalid filters JSON: %v", err))
 30→				return
 31→			}
 32→		}
 33→
 34→		req := search.SearchRequest{
 35→			Filters: filters,
 36→			Limit:   maxRows, // request the maximum; BuildExportQuery caps it
 37→		}
 38→
 39→		// Parse sort.
 40→		if sortParam := q.Get("sort"); sortParam != "" {
 41→			req.Sort = &search.SortInput{
 42→				Field:     sortParam,
 43→				Direction: search.SortDirectionAsc,
 44→			}
 45→			if dirParam := q.Get("sortDir"); dirParam == "DESC" {
 46→				req.Sort.Direction = search.SortDirectionDesc
 47→			}
 48→		}
 49→
 50→		// Parse user location.
 51→		latStr, lngStr := q.Get("userLat"), q.Get("userLng")
 52→		if latStr != "" && lngStr != "" {
 53→			lat, errLat := strconv.ParseFloat(latStr, 64)
 54→			lng, errLng := strconv.ParseFloat(lngStr, 64)
 55→			if errLat != nil || errLng != nil {
 56→				writeJSONError(w, http.StatusBadRequest, "handler: invalid userLat/userLng")
 57→				return
 58→			}
 59→			req.UserLocation = &search.UserLocation{
 60→				Latitude:  lat,
 61→				Longitude: lng,
 62→			}
 63→			if stateParam := q.Get("userState"); stateParam != "" {
 64→				req.UserLocation.State = stateParam
 65→			}
 66→		}
 67→
 68→		// Validate the request.
 69→		if errs := search.ValidateRequest(reg, req); len(errs) > 0 {
 70→			body, _ := json.Marshal(map[string]any{"errors": errs})
 71→			w.Header().Set("Content-Type", "application/json")
 72→			w.WriteHeader(http.StatusBadRequest)
 73→			_, _ = w.Write(body)
 74→			return
 75→		}
 76→
 77→		// Build and execute the export query.
 78→		sqlStr, args, err := search.BuildExportQuery(reg, req, maxRows)
 79→		if err != nil {
 80→			slog.ErrorContext(r.Context(), "handler: build export query", "error", err)
 81→			writeJSONError(w, http.StatusInternalServerError, "handler: failed to build query")
 82→			return
 83→		}
 84→
 85→		rows, err := pool.Query(r.Context(), sqlStr, args...)
 86→		if err != nil {
 87→			slog.ErrorContext(r.Context(), "handler: export query", "error", err)
 88→			writeJSONError(w, http.StatusInternalServerError, "handler: query failed")
 89→			return
 90→		}
 91→		defer rows.Close()
 92→
 93→		// Get exportable field descriptors for CSV columns.
 94→		descriptors := reg.ExportableDescriptors()
 95→
 96→		// Build CSV header row from descriptor labels.
 97→		header := make([]string, len(descriptors))
 98→		for i, d := range descriptors {
 99→			header[i] = d.Label
100→		}
101→
102→		// Scan all rows before writing — allows error handling before
103→		// committing to 200 + CSV headers.
104→		type rowData struct {
105→			unitID          string
106→			institutionName string
107→			city            string
108→			state           string
109→			data            json.RawMessage
110→		}
111→		var rowResults []rowData
112→
113→		for rows.Next() {
114→			var (
115→				unitID, instName, city, state string
116→				lat, lng, distance            *float64
117→				myPrice                       *int
118→				data                          json.RawMessage
119→				blendScore                    *float64 // column 10: unused in export but must be scanned
120→			)
121→			if err := rows.Scan(&unitID, &instName, &city, &state,
122→				&lat, &lng, &distance, &myPrice, &data, &blendScore); err != nil {
123→				slog.ErrorContext(r.Context(), "handler: scan export row", "error", err)
124→				writeJSONError(w, http.StatusInternalServerError, "handler: scan failed")
125→				return
126→			}
127→			rowResults = append(rowResults, rowData{
128→				unitID:          unitID,
129→				institutionName: instName,
130→				city:            city,
131→				state:           state,
132→				data:            data,
133→			})
134→		}
135→		if err := rows.Err(); err != nil {
136→			slog.ErrorContext(r.Context(), "handler: export rows iteration", "error", err)
137→			writeJSONError(w, http.StatusInternalServerError, "handler: query iteration failed")
138→			return
139→		}
140→
141→		// Write CSV response.
142→		w.Header().Set("Content-Type", "text/csv; charset=utf-8")
143→		w.Header().Set("Content-Disposition", `attachment; filename="colleges-export.csv"`)
144→
145→		cw := csv.NewWriter(w)
146→		if err := cw.Write(header); err != nil {
147→			slog.ErrorContext(r.Context(), "handler: write CSV header", "error", err)
148→			return
149→		}
150→
151→		record := make([]string, len(descriptors))
152→		for _, row := range rowResults {
153→			for i, d := range descriptors {
154→				record[i] = extractCoreOrJSONB(d, row.unitID, row.institutionName, row.city, row.state, row.data)
155→			}
156→			if err := cw.Write(record); err != nil {
157→				slog.ErrorContext(r.Context(), "handler: write CSV row", "error", err)
158→				return
159→			}
160→		}
161→		// Append data sources citation section.
162→		writeCitationSection(cw, descriptors)
163→
164→		cw.Flush()
165→		if err := cw.Error(); err != nil {
166→			slog.ErrorContext(r.Context(), "handler: flush CSV", "error", err)
167→		}
168→	}
169→}
