205→// extractCoreOrJSONB returns the CSV cell value for a descriptor.
206→// Core fields (name, city, state, unit_id) are extracted from scanned columns;
207→// all others are extracted from the data JSONB blob via OutputKey.
208→func extractCoreOrJSONB(d search.FieldDescriptor, unitID, instName, city, state string, data json.RawMessage) string {
209→	switch d.Name {
210→	case "name":
211→		return instName
212→	case "city":
213→		return city
214→	case "state":
215→		return state
216→	case "unit_id":
217→		return unitID
218→	default:
219→		if d.OutputKey == "" {
220→			return ""
221→		}
222→		return extractJSONBValue(data, d.OutputKey)
223→	}
224→}
225→
226→// extractJSONBValue navigates a dot-separated path into a JSON blob and
227→// returns the value as a string. Returns "" for nil, missing, or unparseable.
228→func extractJSONBValue(data json.RawMessage, dotPath string) string {
229→	if len(data) == 0 {
230→		return ""
231→	}
232→	parts := strings.Split(dotPath, ".")
233→	var current any
234→	if err := json.Unmarshal(data, &current); err != nil {
235→		return ""
236→	}
237→	for _, part := range parts {
238→		m, ok := current.(map[string]any)
239→		if !ok {
240→			return ""
241→		}
242→		current, ok = m[part]
243→		if !ok {
244→			return ""
245→		}
246→	}
247→	if current == nil {
248→		return ""
249→	}
250→	return fmt.Sprintf("%v", current)
251→}
