253→// writeJSONError writes a JSON error response with the given status code and message.
254→func writeJSONError(w http.ResponseWriter, status int, message string) {
255→	w.Header().Set("Content-Type", "application/json")
256→	w.WriteHeader(status)
257→	_ = json.NewEncoder(w).Encode(map[string]string{"error": message})
258→}
